import{c as e,Q as r,j as a,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"昨天看完了OpenAI 工程师翁家笠 @Trinkle23897 的访谈，给我最大的感受就是他求知欲旺盛、学习能力很强。","description":"","frontmatter":{"title":"昨天看完了OpenAI 工程师翁家笠 @Trinkle23897 的访谈，给我最大的感受就是他求知欲旺盛、学习能力很强。","author":"岛（@Ni_luvya）","date":"2026-04-09T00:00:00.000Z","source":"https://x.com/Ni_luvya/status/2042035590443807043","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-09-@Ni_luvya-807043.md","filePath":"research/tweets/2026-04-09-@Ni_luvya-807043.md","lastUpdated":1779894392000}'),l={name:"research/tweets/2026-04-09-@Ni_luvya-807043.md"};function n(o,t,s,p,d,h){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="昨天看完了openai-工程师翁家笠-trinkle23897-的访谈-给我最大的感受就是他求知欲旺盛、学习能力很强。" tabindex="-1">昨天看完了OpenAI 工程师翁家笠 @Trinkle23897 的访谈，给我最大的感受就是他求知欲旺盛、学习能力很强。 <a class="header-anchor" href="#昨天看完了openai-工程师翁家笠-trinkle23897-的访谈-给我最大的感受就是他求知欲旺盛、学习能力很强。" aria-label="Permalink to &quot;昨天看完了OpenAI 工程师翁家笠 @Trinkle23897 的访谈，给我最大的感受就是他求知欲旺盛、学习能力很强。&quot;">​</a></h1><p>他在 2022 年加入 OpenAI — @Ni_luvya</p><p><strong>來源</strong>：<a href="https://x.com/Ni_luvya/status/2042035590443807043" target="_blank" rel="noreferrer">https://x.com/Ni_luvya/status/2042035590443807043</a><strong>作者</strong>：岛（@Ni_luvya） <strong>發布日期</strong>：2026-04-09 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文 <strong>統計</strong>：1,022 likes · 209 retweets · 1,141 bookmarks · 179,206 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>昨天看完了OpenAI 工程师翁家笠 @Trinkle23897 的访谈，给我最大的感受就是他求知欲旺盛、学习能力很强。</p><p>他在 2022 年加入 OpenAI，并且是 OpenAI 一系列核心模型背后的核心贡献者之一，从 GPT-3.5、GPT-4、再到 GPT-5，你能看到的那些关键跃迁里，都有他的身影。他最主要的贡献，是以下三个词：强化学习、post-training、infra。</p><p>我在他的个人网站里搜到的经历见图一，下面是看完整期播客的一些感受：</p><p>🍃一、求知欲强且找到了自己的学习方法：</p><p>发现自己需要更长的时间构建知识树，需要比常人花2-3倍时间去理解context和底层逻辑。</p><p>他的学习的兴趣从何而来？他认为这是对自己的投资、对未来的投资。</p><p>并且在学习的过程中他会通过正反向筛选来构建自己的技能树：</p><ol><li>正向筛选就是他很早就发现自己喜欢奥数，并且持续投入能获得比别人更快的成就。</li><li>同时会果断放弃投入比产出低的，例如打篮球，经常被别人按着打；例如跆拳道，实战会被揍；对语文不感兴趣等等。</li></ol><p>虽然学得慢，但他找到了适合自己的学习方式：</p><ol><li>iPad的Safari没有代码编辑器，他用iPad裸打代码，其实是完全不必要的，不过这种方式强迫他在大脑中构建程序逻辑，训练他的思考和反应能力。</li><li>学得慢就提前学。比如初二学完高中数学，初三开始学微积分。</li><li>GPA不重要，短时间达到够用的成绩就行，不浪费时间。学对自己重要的东西。</li></ol><p>🍃二、构建自己的评价体系： 当他意识到清华内部大家都认为GPA越高越好、PhD远比Master好，并为之奋斗的时候，他认为自己的目标是找工作，GPA选择在最少时间达到够用的成绩就行，重点在于在行业里积累经验。</p><p>他认同自己导师的评价指标：论文、比赛、三位数以上的GitHub Star</p><p>在清华期间开源自己搜集的所有作业和材料，打破信息差。因为他认为有些人不擅长搜索，但很有能力，不必要浪费时间在这上面。</p><p>他希望获得认可，如Github的star数，如最大化自己在OpenAI blog上出现名字的次数，只要他在RL，每个大模型发blog都尽可能能带上名字，从而实现生产力的scale up ，让自己的工作量转化为所有核心产品的贡献。</p><p>🍃三、在人生节点，他是如何做决策的：</p><ol><li><p>为什么不读PhD：前面提到的，跟之前提到他的价值体系有关，认为自己要进入工业界而不是学术界，“教一个researcher做好enginerring, 要远比教一个engineer如何做好research难得多”，因此他就不需要PhD来浪费生命，更看重Infra.</p></li><li><p>在ChatGPT爆发前，为什么手握OpenAI、幻方、谷歌、英伟达的offer，选择了OpenAI: 不想进谷歌，不愿意当螺丝钉，他想进人才密度最高的地方，当时到幻方做RL infra是备选。</p></li></ol><p>🍃四、主播也很会提问题，例如大家都在吐槽OpenAI已经不open了，翁家笠他也曾经一直在做开源相关的事情，这不冲突吗？</p><p>对于OpenAI 这样的大模型公司来说生死线是infra迭代的时间。现阶段不进行闭源就无法持续融资，解决算力成本和实验开销，从而推动技术。</p><p>他说其实John Schulman曾经问过是否将RL Infra开源，但为了公司竞争力和安全性，还是拒绝了。也就是现阶段他调整了个人优先级，尽管曾通过开源天授、退学Online签证查询系统来打破信息差，但认同现阶段顶尖模型公司需要通过闭源来做博弈。</p><p>如果未来创业，他大概会选择产品方向。因为他认为技术的复杂程度不重要，能精准抓到用户需求才重要。退学Online在早期甚至是手动更新，但解决了他们的燃眉之急（他做过的项目介绍见图二）。他自己对纯研究、发论文没什么兴趣，更喜欢有多少人记得、使用他做的东西。</p><p>🍃五、主播问到：”如果AI能解决一个世界难题，他希望解决什么？““如何预测未来” 由此展开了宿命论的探讨</p><p>他认为这个世界是个确定论，人的命运是可以被预测的，我们生活在一个确定性的马尔可夫过程里（播客对我这种小白来说很友好，专业术语都有解释，如果你也需要可以看图三、图四）需要提前生成剧本。</p><p>他甚至认为，人是没有自由意志的，大脑里在想什么，对话中下一个单词说什么、问什么问题都是宇宙大爆炸的那一刻就确定了。</p><p>主持人真的很会提问！下一个问题是如果是宿命论那为什么他要投资未来：</p><ol><li>未来的我帮助过去的我，完成某些决策。所以要投资自己，投资未来 例如他自己在高三蹦出的“要创造影响力”的想法，是未来的他给过去的自己发送的信息</li><li>秉持宿命论，他的生存策略不是等待一切线性结果的到来，而是忘掉这一切，假装不知道，然后尽情享受人生体验。坚信西西弗斯是幸福的，活着是在确定性的循环里寻找当下的意义。</li></ol><p>原播客不太长，只有2小时。地址：<a href="https://www.youtube.com/watch?v=I0DrcsDf3Os" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=I0DrcsDf3Os</a></p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：OpenAI 核心工程師翁家笠（GPT-3.5/4/5 RL post-training 核心貢獻者）的人生哲學訪談整理，主題是學習方法論、職涯決策框架和宿命論。與 Claude Code 或 AI coding 工作流無直接關係。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>學習方法</strong>：需要比常人 2-3 倍時間構建知識樹，但通過「正向篩選+及早開始」補足</li><li><strong>職涯框架</strong>：GPA 夠用就好，重心在行業經驗積累；「教工程師做研究比教研究員做工程難」</li><li><strong>選 OpenAI 的邏輯</strong>：進人才密度最高的地方，不願當螺絲釘</li><li><strong>宿命論</strong>：認為世界是確定性馬可夫過程，人無自由意志，但策略是「忘掉宿命、享受當下」</li><li><strong>技術觀</strong>：技術複雜度不重要，精準抓到用戶需求才重要（退學 Online 早期甚至手動更新）</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>1,022 likes · 1,141 bookmarks · 179,206 views</li><li>原始播客：youtube.com/watch?v=I0DrcsDf3Os（2 小時）</li><li>翁家笠貢獻：GPT-3.5、GPT-4、GPT-5 的 RL post-training 和 infra</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>這是成功工程師的個人成長訪談，不是技術或工作流指南</li><li>與 Claude Code 技術生態完全無關，在這批 tweets 的主題脈絡中屬異類</li><li>宿命論哲學有趣但無可操作性</li><li>「技術複雜度不重要」的觀點適用於產品思維，但與工程師日常工作的技術深度無矛盾</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>1/10</td><td>無 Claude Code 或工作流相關內容</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>宿命論+投資未來的框架有個人特色</td></tr><tr><td>C. 證據品質 (20%)</td><td>7/10</td><td>有原始播客來源，第一手內容</td></tr><tr><td>D. 技術深度 (15%)</td><td>4/10</td><td>個人經驗分享，無技術實作細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>4/10</td><td>職涯哲學有一定普適性，但非本批主題</td></tr><tr><td><strong>加權總分</strong></td><td><strong>3.45/10</strong></td><td></td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：內容與 Claude Code 工作流和 cc-workspace 完全不相關。訪談本身有價值，但應歸類到 career-wiki 而非 AI coding 研究。</p>',44)])])}const g=e(l,[["render",n]]);export{u as __pageData,g as default};
